import json
from datetime import datetime

owner_assignments_file = locals()['var_functions.query_db:8']
closed_cases_data = locals()['var_functions.query_db:6']

# Load all owner assignments
with open(owner_assignments_file, 'r') as f:
    owner_assignments = json.load(f)

# Build a dictionary of case assignments
case_assignments = {}
for assignment in owner_assignments:
    case_id = assignment['caseid__c']
    if case_id not in case_assignments:
        case_assignments[case_id] = []
    case_assignments[case_id].append(assignment)

# Get non-transferred cases (exactly one owner assignment)
non_transferred_case_ids = set()
for case_id, assignments in case_assignments.items():
    if len(assignments) == 1:
        non_transferred_case_ids.add(case_id)

# Process closed cases from past 4 months
agent_handle_times = {}
agent_case_counts = {}

for case in closed_cases_data:
    case_id = case['id']
    clean_case_id = case_id.lstrip('#')  # Remove leading #

    # Only process non-transferred cases
    if clean_case_id not in non_transferred_case_ids:
        continue

    owner_id = case['ownerid'].lstrip('#')  # Clean owner ID
    created_str = case['createddate']
    closed_str = case['closeddate']

    # Skip if dates are None or invalid
    if not created_str or not closed_str or closed_str == 'None':
        continue

    # Parse dates and calculate handle time in hours
    try:
        created = datetime.fromisoformat(created_str.replace('Z', '+00:00'))
        closed = datetime.fromisoformat(closed_str.replace('Z', '+00:00'))
        handle_time_hours = (closed - created).total_seconds() / 3600

        # Aggregate by agent
        if owner_id not in agent_handle_times:
            agent_handle_times[owner_id] = 0
            agent_case_counts[owner_id] = 0

        agent_handle_times[owner_id] += handle_time_hours
        agent_case_counts[owner_id] += 1
    except:
        continue

# Calculate average handle time for agents with more than 1 case
agent_averages = {}
for owner_id in agent_handle_times:
    if agent_case_counts[owner_id] > 1:
        agent_averages[owner_id] = agent_handle_times[owner_id] / agent_case_counts[owner_id]

print('__RESULT__:')
print(json.dumps({
    'total_agents': len(agent_averages),
    'agents_with_cases': agent_case_counts,
    'average_handle_times': agent_averages
}))

